                  <motion.tr key={task.id} variants={item} className={`hover:bg-slate-50 dark:hover:bg-slate-700/20 transition-colors ${selected.has(task.id) ? 'bg-blue-50/50 dark:bg-blue-500/5' : ''}`}>
                    <td className="px-4 py-3.5">
